xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:94:\"Open Channels FM: Preparing Your WooCommerce Store for the AI Era: Data and Catalog Management\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://openchannels.fm/?p=535677\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:100:\"https://openchannels.fm/preparing-your-woocommerce-store-for-the-ai-era-data-and-catalog-management/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:365:\"As WooCommerce continues to evolve in its integration with AI technologies, one theme stands out: the importance of structured and accessible data for store success. Conversations in a recent episode illuminated how a well-managed product catalog is the backbone of leveraging AI features, both now and in the future. Store owners and developers are urged [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 03 Mar 2026 12:38:17 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:29;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:96:\"Open Channels FM: What’s New at CloudFest Hackathon 2026: Trends, Changes, and Creative Energy\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=1650438\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:97:\"https://openchannels.fm/whats-new-at-cloudfest-hackathon-2026-trends-changes-and-creative-energy/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:185:\"In this episode enjoy a chat about the CloudFest Hackathon 2026\'s history, future initiatives, and community engagement, emphasizing inclusivity, mentorship, and project sustainability.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 03 Mar 2026 10:22:42 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:30;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:11:\"Matt: Emacs\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=151334\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"https://ma.tt/2026/03/emacs/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:740:\"<p class=\"wp-block-paragraph\">People are doing pretty interesting things with <a href=\"https://www.gnu.org/software/emacs/\">Emacs</a> (now on version 30.2!) these days, if you haven&#8217;t checked in recently. The bleeding edge has always been people into <a href=\"https://orgmode.org/\">Org Mode</a>. <a href=\"https://sachachua.com/blog/2026/01/using-whisper-el-to-capture-text-to-speech-in-emacs/\">Sacha Chua has hooked up Whisper to Emacs</a> to talk to it.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Emacs is probably one of the first and best examples of self-modifying software that contours to your brain. With vibe coding, we may get back to that space where everyone&#8217;s personal setup is like a crazy specific Emacs config file.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 03 Mar 2026 10:11:53 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:31;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:63:\"Open Channels FM: How Freelancers Can Tame Digital Distractions\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=1650174\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:70:\"https://openchannels.fm/how-freelancers-can-tame-digital-distractions/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:173:\"Starting conversations around strategies to reduce digital distractions, emphasizing boundaries for emails, social media habits, and personalizing routines for better focus.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 03 Mar 2026 09:29:53 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:32;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:71:\"Gutenberg Times: Schedule of WordCamp Asia Birgit’s selected sessions\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://gutenbergtimes.com/?p=44484\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:79:\"https://gutenbergtimes.com/schedule-of-wordcamp-asia-birgits-selected-sessions/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:6541:\"<p class=\"wp-block-paragraph\">This year&#8217;s WordCamp Asia just published the first version of its <a href=\"https://asia.wordcamp.org/2026/schedule/\">schedule with sessions and workshops</a>. Contributor Day also has a few workshop slots. If you registered for Contributor Day you are looking at three days of learning and discussions.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Here is my personal list of talks and workshops, mostly about the block editor, themes or AI in WordPress. I will update the post with the video links after WordCamp Asia once the recordings are uploaded to WordPress TV. </p>\n\n\n\n<p class=\"wp-block-paragraph\">Livestreams are available on April 10 and 11 on the three session tracks, Foundation, Growth and Enterprise. Times are all local Indian Standard time (UTC +5.30).</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Updated March 2, 2026</strong>,</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://asia.wordcamp.org/2026/schedule/\">The schedule</a> has a few placeholder spots for </p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Journalism and the Open Web </li>\n\n\n\n<li>AI and WordPress </li>\n\n\n\n<li>And quite few TBD for talks and workshop</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">The schedule for the Contributor Day hasn&#8217;t been finalized either. It&#8217;s unclear when my workshop <a href=\"https://asia.wordcamp.org/2026/session/building-a-block-theme-from-scratch/\"><strong>Building a block theme from scratch</strong></a> will take place. There are three workshop slots reserved. We will have a <a href=\"https://asia.wordcamp.org/2026/wordpress-7-0-release-on-contributor-day/\">WordPress 7.0 Release</a> ssession and Open-source Library spaces as well. </p>\n\n\n\n<p class=\"wp-block-paragraph\">The conference days also have six workshop slots that are still &#8220;TBA&#8221;. </p>\n\n\n\n<p class=\"wp-block-paragraph\">The program team is working on the final version of the schedule. Make sure to check back on weekly basis.  </p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<h2 class=\"wp-block-heading\">Birgit&#8217;s selected sessions</h2>\n\n\n\n<h3 class=\"wp-block-heading\">April 10, 2026</h3>\n\n\n\n<p class=\"wp-block-paragraph\">After opening remarks and introduction of speakers the day begins with</p>\n\n\n\n<p class=\"wp-block-paragraph\">10 am <a href=\"https://asia.wordcamp.org/2026/session/fireside-chat/\"><strong>Fireside Chat with Mary Hubbard</strong></a></p>\n\n\n\n<p class=\"wp-block-paragraph\">1:00 pm <a href=\"https://asia.wordcamp.org/2026/session/from-static-to-dynamic-mastering-the-interactivity-api/\"><strong>From Static to Dynamic: Mastering the Interactivity API</strong></a> with Ryan Welcher</p>\n\n\n\n<p class=\"wp-block-paragraph\">2:50 pm <a href=\"https://asia.wordcamp.org/2026/session/lost-found-in-ai-wonderland-an-honest-journey-through-hype-headaches-and-real-wins/\"><strong>Lost &amp; Found in AI Wonderland: An Honest Journey Through Hype, Headaches, and Real Wins</strong></a> with Nirav Mehta</p>\n\n\n\n<p class=\"wp-block-paragraph\">3:55 pm <a href=\"https://asia.wordcamp.org/2026/session/ten-times-the-value-why-automation-is-worth-the-investment-in-open-source/\"><strong>Ten Times the Value: Why Automation Is Worth the Investment in Open Source</strong></a> with Jonathan Desrosiers</p>\n\n\n\n<h3 class=\"wp-block-heading\">April 11, 2026 </h3>\n\n\n\n<p class=\"wp-block-paragraph\">9:15 am  <strong><a href=\"https://asia.wordcamp.org/2026/session/wordpress-playground-ai-building-autonomous-testing-pipelines/\">WordPress Playground + AI: Building Autonomous Testing Pipelines</a> </strong>with Fellyph Cintra</p>\n\n\n\n<p class=\"wp-block-paragraph\">11:15 <strong><a href=\"https://asia.wordcamp.org/2026/session/entity-first-optimization-how-to-make-wordpress-content-machine-readable/\">Entity-First Optimization: How to Make WordPress Content Machine-Readable</a> </strong>with Adeline Dahal</p>\n\n\n\n<p class=\"wp-block-paragraph\">11:35 am: <strong><a href=\"https://asia.wordcamp.org/2026/session/from-chaos-to-clarity-scaling-teams-with-block-theme-standards/\">From Chaos to Clarity: Scaling Teams with Block Theme Standards</a></strong> with JC Palmes</p>\n\n\n\n<p class=\"wp-block-paragraph\">12:25 pm <a href=\"https://asia.wordcamp.org/2026/session/build-for-what-comes-next-how-enterprise-wordpress-is-powering-the-agentic-future/\"><strong>Build for What Comes Next: How Enterprise WordPress Is Powering the Agentic Future</strong></a> with James Giroux</p>\n\n\n\n<p class=\"wp-block-paragraph\">3:00 pm Don&#8217;t miss: <a href=\"https://asia.wordcamp.org/2026/session/closing-keynote-wordpress-co-founder-matt-mullenweg/\"><strong>Closing Keynote: WordPress Co-Founder Ma.tt Mullenweg</strong></a></p>\n\n\n\n<h2 class=\"wp-block-heading\">First time in Mumbai?</h2>\n\n\n\n<p class=\"wp-block-paragraph\">The communication team published some really cool posts about Mumbai and India, which is super helpful for anyone heading there for their first time.</p>\n\n\n\n<div class=\"wp-block-columns has-light-background-background-color has-background is-layout-flex wp-container-core-columns-is-layout-8f761849 wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<h3 class=\"wp-block-heading\">First-time WordCamper</h3>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://asia.wordcamp.org/2026/how-to-make-the-most-of-your-first-wordcamp/\">How to Make the Most of Your First WordCamp Asia?</a></li>\n\n\n\n<li><a href=\"https://asia.wordcamp.org/2026/about-the-venue/\">Venue</a></li>\n\n\n\n<li><a href=\"https://asia.wordcamp.org/2026/how-to-prepare-for-contributor-day/\">How to Prepare for Contributor Day?</a></li>\n\n\n\n<li><a href=\"https://asia.wordcamp.org/2026/5-career-conversations/\">5 Career Conversations You Will Have at WCAsia26</a></li>\n</ul>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<h3 class=\"wp-block-heading\">Food, Culture and Travel</h3>\n\n\n\n<ul class=\"wp-block-list has-small-font-size\">\n<li><a href=\"https://asia.wordcamp.org/2026/food-walk/\">Your Next Bite Is Here</a></li>\n\n\n\n<li><a href=\"https://asia.wordcamp.org/2026/sim-cards-internet-and-upi-payments-made-simple/\">SIM Cards, Internet, and UPI Payments Made Simple</a></li>\n\n\n\n<li><a href=\"https://asia.wordcamp.org/2026/namaste-india-guide-to-indian-culture/\">Namaste India! Guide to Indian Culture</a></li>\n\n\n\n<li><a href=\"https://asia.wordcamp.org/2026/mumbai-on-a-plate/\">Mumbai on a Plate</a></li>\n\n\n\n<li><a href=\"https://asia.wordcamp.org/2026/things-to-do-in-mumbai/\">Things to do in Mumbai</a></li>\n</ul>\n</div>\n</div>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 02 Mar 2026 12:01:31 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:18:\"Birgit Pauli-Haack\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:33;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:66:\"Open Channels FM: Open Channels New YouTube Channel and Newsletter\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=1650400\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:73:\"https://openchannels.fm/open-channels-new-youtube-channel-and-newsletter/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:80:\"Host Bob Dunn announces  a new YouTube channel and a new newsletter and roundup.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 02 Mar 2026 11:45:05 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:34;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:70:\"Open Channels FM: Omnisend Continues Their Support of Open Channels FM\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=1650182\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:77:\"https://openchannels.fm/omnisend-continues-their-support-of-open-channels-fm/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:141:\"Omnisend continues to sponsor us, offering a powerful marketing platform for ecommerce. They provide easy migration support and so much more.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 02 Mar 2026 09:46:50 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:35;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:18:\"Matt: Sunday Links\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=151324\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://ma.tt/2026/03/sunday-links/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:2362:\"<p class=\"wp-block-paragraph\">Five items:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://transparency.automattic.com/2026/02/23/transparency-report-update-july-december-2025/\">Automattic&#8217;s new transparency report is up</a>, and <a href=\"https://transparency.automattic.com/wordpress-dot-com/intellectual-property/intellectual-property-2025-jul-1-dec-31/\">TorrentFreak covers how AI-generated notices have been flooding the system</a>. We don&#8217;t talk about it much, but for two decades now Automattic has been a fierce fighter for free speech on behalf of our customers and journalists. Our legal team has gotten a big upgrade in the past 15 months so look for more in this area.</li>\n\n\n\n<li>WordPress 7.0 is shaping up to be a great release, and we&#8217;re moving fast! As someone noted, after <a href=\"https://make.wordpress.org/core/2026/02/18/wordpress-7-0-product-review-meeting-with-matt/\">the product review</a>, <a href=\"https://x.com/SteveJBurge/status/2027152882445775168\">we got the new Connectors setting screen in beta 2 at AI speed</a>.</li>\n\n\n\n<li>Yesterday, <a href=\"https://tinkertendo.com/\">TinkerTendo</a> hosted a fun <a href=\"https://luma.com/a6t92ohv\">BioArena Hackathon</a>. <a href=\"https://cloudup.com/cYjePWS3QRx\">From the pics, it looked like a great event</a>.</li>\n\n\n\n<li>Kudos to WP community member Matt Medeiros, <a href=\"https://www.youtube.com/watch?v=zcKBDzrER3g\">who used AI to spin up a quick webapp to help his community</a> track which streets had been plowed after that crazy snowstorm. Making local communities better is definitely part of the WordPresser ethos.</li>\n\n\n\n<li><a href=\"https://claude.com/import-memory\">Claude&#8217;s hack to import your memory</a> is an amazing application of what I hoped for with the <a href=\"https://wordpress.org/data-liberation/\">Data Liberation push on WordPress.org</a>. However, it&#8217;s just re-arranging deck chairs on the Titanic; what you really want is for that memory to be personal to you and work with every model, which is what <a href=\"https://github.com/openclaw/openclaw\">OpenClaw</a> and its many claw descendents, like <a href=\"https://github.com/zeroclaw-labs/zeroclaw\">ZeroClaw</a>, do for you. It reminds me of <a href=\"https://tantek.com/presentations/2005/01/attentionxml.html\">Tantek&#8217;s 2005 Attention.xml presentation</a>.</li>\n</ul>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sun, 01 Mar 2026 18:55:49 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:36;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:83:\"Gutenberg Times: Gutenberg Changelog #127 – WordPress 7.0 Beta and Gutenberg 22.6\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:53:\"https://gutenbergtimes.com/?post_type=podcast&p=44570\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:78:\"https://gutenbergtimes.com/podcast/gutenberg-changelog-127-wordpress-7-0-beta/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:68978:\"<p class=\"wp-block-paragraph\">In Episode 127 of the GT Changelog podcast, Birgit Pauli-Haack and Jessica Lyschik dive deep into the upcoming release of WordPress 7.0, focusing on the features arriving with beta 2 and their impact on users and developers. They begin by emphasizing the importance of testing betas, especially for plugin and theme creators, highlighting how early testing helps prevent compatibility issues at launch. A walk-through of the beta testing process, tools like the beta tester plugin, and considerations for time zone differences during the official release (scheduled for April 9th) are discussed.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The majority of their conversation centers around the headline features of WordPress 7.0. Real-time collaboration steals the spotlight, now allowing multiple users to edit posts and pages simultaneously—streamlining workflows and minimizing version conflicts. The episode also celebrates the introduction of visual revisions within the block editor, making change tracking clearer and more intuitive. Other notable updates include responsive block visibility controls, enhanced navigation and submenu options, improved lightbox support for gallery blocks, and the long-awaited introduction of the icon and breadcrumbs blocks.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Birgit Pauli-Haack and Jessica Lyschik also discuss the new content-only pattern editing feature, revamped backend color schemes, and incremental improvements for both end-users and developers, such as the font library UI and under-the-hood advances. They note that some planned features, like the playlist and tabs blocks, did not make the cut for 7.0 but might arrive in future releases. The episode ends with practical advice: test your sites early and stay informed to ensure a seamless transition to WordPress 7.0.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://gutenbergtimes.com/podcast/gutenberg-changelog-127-wordpress-7-0-beta/\">Show Notes</a> / <a href=\"https://gutenbergtimes.com/podcast/gutenberg-changelog-127-wordpress-7-0-beta/\">Transcript</a></p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Editor: <a href=\"https://www.linkedin.com/in/sandy-reed/\">Sandy Reed</a></li>\n\n\n\n<li>Logo: <a href=\"https://markuraine.com/\">Mark Uraine</a></li>\n\n\n\n<li>Production: <a href=\"https://icodeforapurpose.com\">Birgit Pauli-Haack</a></li>\n</ul>\n\n\n\n<p class=\"has-larger-font-size wp-block-paragraph\" id=\"shownotes\"><strong>Show Notes</strong></p>\n\n\n\n<h2 class=\"wp-block-heading\">Special guest: Jessica Lyschik</h2>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://x.com/jessicalyschik\">https://x.com/jessicalyschik</a></li>\n\n\n\n<li><a href=\"https://www.youtube.com/@jessicalyschik\">https://www.youtube.com/@jessicalyschik</a></li>\n\n\n\n<li><a href=\"https://www.youtube.com/redirect?event=channel_description&amp;redir_token=QUFFLUhqa2tsT25ETnVSM20xS3ZoNDhpTkhwUVhlM2J0UXxBQ3Jtc0tsY2NmeEdxT01xdEMzMlR4WWxjYll2bGoyMXlSZVZFZm82alVtS3hpdW01Y3U1R3U0RGVBT19lbEhQeXNYeTcxZ0EwaVg4YUlYV2ZGR085ZXA1U0pYYzdSelRnejR5cDBHUm1pZDRpQi1fdHRPbkw3UQ&amp;q=https%3A%2F%2Fprofiles.wordpress.org%2Fluminuu\">profiles.wordpress.org/luminuu</a></li>\n\n\n\n<li><a href=\"https://www.youtube.com/playlist?list=PLtf0_A0KILu5lspB8oXQjinPhIe87s3nJ\">Greyd Conversations, to be found on YouTube</a></li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">WordPress 7.0</h2>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://make.wordpress.org/test/2026/02/20/help-test-wordpress-7-0/\">Help Test WordPress 7.0</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2026/02/24/iframed-editor-changes-in-wordpress-7-0/\">Iframed Editor Changes in WordPress 7.0</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2025/12/11/planning-for-7-0/#comment-48392\" id=\"https://make.wordpress.org/core/2025/12/11/planning-for-7-0/#comment-48392\" type=\"link\">What made it into WordPress 7.0</a> </li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2026/02/25/whats-new-in-gutenberg-22-6-25-february/\">What’s new in Gutenberg 22.6? (25 February)</a></li>\n</ul>\n\n\n\n<p class=\"has-large-font-size wp-block-paragraph\">Stay in Touch</p>\n\n\n\n<div class=\"wp-block-group\"><div class=\"wp-block-group__inner-container is-layout-flow wp-block-group-is-layout-flow\">\n<ul class=\"wp-block-list\">\n<li>Did you like this episode? <a href=\"https://lovethepodcast.com/gutenbergchangelog\"><strong>Please write us a review </strong></a></li>\n\n\n\n<li>Ping us on X (formerly known as Twitter) or send DMs with questions. <a href=\"https://twitter.com/gutenbergtimes\">@gutenbergtimes </a>and <a href=\"https://twitter.com/bph\">@bph</a>.</li>\n\n\n\n<li><em>If you have questions or suggestions, or news you want us to include, send them to <a href=\"mailto:changelog@gutenbergtimes.com\">changelog@gutenbergtimes.com</a>. </em></li>\n\n\n\n<li><em>Please write us a review on iTunes! <a href=\"https://gutenbergtimes.com/itunes/\">(Click here to learn how)</a></em></li>\n</ul>\n</div></div>\n\n\n\n<p class=\"has-large-font-size wp-block-paragraph\" id=\"transcript\"><strong>Transcript</strong></p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack:</em> So welcome to our 127th episode of the Gutenberg Changelog podcast. In today&#8217;s episode, we will talk mostly about WordPress 7.0 because Beta 2 has been out and a little bit about Gutenberg 22.6, but most of what&#8217;s in that release is actually coming to WordPress 7.0. </p>\n\n\n\n<p class=\"wp-block-paragraph\">I&#8217;m your host, Birgit Pauli-Haack, curator at the Gutenberg Times and a full-time core contributor for the WordPress open source project, sponsored by Automattic. And today, Jessica Lyschik is with me on the show again, and we will tackle most of the WordPress 7.0 updates. Jessica is a core contributor to WordPress, default theme co-lead for Twenty Twenty-Four, speed building champion Twenty Twenty-Five, and works as a senior developer for Grade, a company building WordPress products for agencies and large companies. And Jessica is a regular host on the Grade Conversations to be found on YouTube. How are you today, Jessica? Welcome to the show again.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik:</em> Thanks for having me. I&#8217;m good. I&#8217;m good. I mean, the sun is shining outside, so I&#8217;m expecting hopefully a nice workday today and then catch some sun rays because it&#8217;s been a long winter here. Yeah, it&#8217;s been very cold, very moody, cloudy. So the sun is very nice. Having some sunshine is a very nice change.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack:</em> Yeah, I was walking the streets of Munich the other day and I saw the little plants kind of coming out, crocuses and whites and yellow. So spring is coming.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik: </em>Definitely, definitely.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>And it&#8217;s— I actually saw a sunrise at 6:30 in the morning. So the days are getting longer too, which is part of my mood changing thing. Yeah. </p>\n\n\n\n<h3 class=\"wp-block-heading\">What’s Released &#8211; WordPress 7.0</h3>\n\n\n\n<p class=\"wp-block-paragraph\">So WordPress 7.0 comes in big steps and WordPress 7.0 Beta 2 was released just yesterday and we&#8217;re recording this on February 27th. So let&#8217;s go through the list of things that actually made it into 7.0. I&#8217;m also sharing in the show notes, not only the list, but also a link to the help test WordPress 7.0 that the test team has put together with some nice instructions and videos on how things are supposed to work. And you have to— can go in and test if they&#8217;re actually working like that or if something else is breaking. And you ask dear listeners to help do that. I also always kind of say, the best way to learn what&#8217;s in WordPress 7.0 is to heed to the call of testing, because that&#8217;s the first step to learn what&#8217;s working for you, what works with your sites and with your plugins. And it will be really helpful to know this before the release comes out. So if you just follow the instructions on how to present feedback and bug reports. Your team has started testing. </p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: When you have a plugin and you do not look at the Beta versions or release candidates and suddenly the release date rolls around and you&#8217;re not prepared and clients update their websites and then they say, hey, my site&#8217;s broken, then you&#8217;re in trouble. So avoid that as best as possible. That&#8217;s why I&#8217;m glad that we have Beta phase and release candidate phase so we can like really have a closer look. And it&#8217;s so easy with the Beta tester plugin. To be honest, that&#8217;s still the one way I&#8217;m using it, just installing the plugin. I configure the default configuration a little bit differently only to show me Beta and release candidates versions. And then it&#8217;s just hit update and go for it with whatever installation you have at the moment. So that&#8217;s actually, I find this to be one of the easiest ways without needing to have big technical knowledge about that. Of course there&#8217;s WP CLI, there&#8217;s many other ways you can achieve that, but for me, this is probably the easiest and can be thrown on any installation, local or online, probably not live sites, but any staging or testing environment that you have.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: So exactly. And it&#8217;s a good point. Don&#8217;t test this on a live site.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Yeah. Things can break. I mean, that&#8217;s why it&#8217;s called a Beta version or release candidate. Things are supposed to break. I spotted an issue this morning with something, not a big issue, but it is an issue. So we have to look into this, but we still have time. How long are we away? 6 weeks, I think about 6 weeks.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: So yeah, April 9th is the final release date. So we are a little bit 5 weeks more than 6 weeks.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: And it will be, I just saw the note, will be released during Contributor Day at WordCamp Asia. So some of the release squad members will be in Mumbai to hit the big button. But of course, it&#8217;s all remotely and you can do it from anywhere. So it doesn&#8217;t really matter where the release squad is. The only thing that might screw it a little bit, skew it, not screw it, skew it a little bit is the time difference between where the other release squad members are and the ones in Mumbai. But for Europe, it&#8217;s a 3.5-hour time difference. So it&#8217;s not that big of a deal. You just need to organize it.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Yeah, usually they are fast in Europe, their releases are in the evening. So something around 7 PM, 8 PM sometime. It depends on when the dates are announced and the times. So it will be a bit earlier for us in the day, but still like afternoon-ish. So not in the middle of the night. So, but of course, if you move further to US time zones, like East Coast, West Coast is particularly early for them, I guess. If it&#8217;s fun, it could be like early morning for them.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah, could be in the middle of the night.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Oh no, no, we have to, we have to think backwards. It will be like, I don&#8217;t know, but is it like in the afternoon on the 9th? Do you know more details about that?</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: I was looking for the release party. Post, but I haven&#8217;t seen it.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: I mean, there&#8217;s an overview post somewhere.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah. I remember that. Yeah. On the Make blog. Definitely. I&#8217;m just looking at it when the release party schedule is.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: I&#8217;ll see if, uh, there&#8217;s only a date so far on the, on the overview.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah. Beta release was about 3 PM UTC. So that&#8217;s 4 o&#8217;clock in the afternoon in Europe. -9, that&#8217;s about 7 o&#8217;clock in the morning.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: It&#8217;s early morning. Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: In Pacific time. Yeah. So about that time. Yeah. I&#8217;ll get a better look at that when we get closer to see when they actually schedule the release parties. But it&#8217;s always great fun to be in the core channel to kind of see it coming together.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah. So that&#8217;s about the process. April 9th, we mentioned it, is the release. We have release candidate. So Beta is the feature freeze. So after that, only bug fixes are going to be merged into core. Release candidate 1 is on March 19th, and that is considered a string freeze. There will be release candidate 1, 2, and 3, and only things that are— don&#8217;t have a string. Well, the reason why they do string freeze is because then the translator can start translating the version or the new strings into their respective languages. And to give them about 3 weeks to 4 weeks is a good number. But when you don&#8217;t do string freeze, then they have to start all over again when the new version comes out.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: So many things change. I mean, things will change. Maybe there&#8217;s always the thing that a bug appears and maybe strings have to be changed. So there&#8217;s always some moving parts, but it is way much reduced if you would just, if you&#8217;re stopping to actually make massive changes so people can catch up with things and then when it&#8217;s just a few more strings that need to be adjusted or retranslated, then it&#8217;s not like 500 new strings, but only 5 the day before the release. So yeah, it makes total sense. I mean, it has worked great over the past many years that we&#8217;ve been doing this like that.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Absolutely. Yeah. So now with all the talk about the release, what&#8217;s actually going to be in WordPress 7.0? And there have been quite a few. So there was a roadmap and then there were these tracking issues that are on the Gutenberg repo. So there is not a whole lot of mystery behind what&#8217;s coming, but we definitely should talk through that. And one of the biggest features is the real-time collaboration. So now the message that somebody else is editing your post will go away, or it will still be there, but you still can access the post and then you can see who else is working on the post. And you can have more than one person in the post or in the page to actually edit that and not get into trouble with losing content. So that&#8217;s a feature that has been a long time coming. And it&#8217;s also something that has been tested already in the enterprise section for, I think, a little over a year or half a year since August last year. So, and now it comes to WordPress core. So it&#8217;s really cool. I&#8217;ve, I like it.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: I have not seen it in action yet because I mostly work on things where it&#8217;s only me and rarely anyone else, but I&#8217;ve seen the notes feature. This is like the kind of site quest, if you will, which has been already around since 6.9, if I remember correctly.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Right.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: But yeah, I&#8217;ve just opened the GitHub issue around it that is linked in the testing post. And it&#8217;s quite interesting. It will be interesting to see. I think we have to spin up a session with my colleagues and all go into one page and see what it looks like, how it feels like.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: So yeah, there are some avatar bubbles showing up on multiple places. Yeah, it&#8217;s kind of in the headline and also when they&#8217;re both there. And also if they&#8217;re the notes and the real-time collaboration are kind of merging now. So the same avatars that show up in the notes will also show up in the, in as where the cursor is. So it&#8217;s kind of really interesting to see. I think it&#8217;s not only for enterprise, it&#8217;s also for if you have a blog site, you probably also have a designer or a person that manages your media. You can all be in the post and kind of do things just right before publishing and you don&#8217;t have to coordinate, get out of the post, get into the post. What do we change? Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: It will save things. Even if you have a team of two, it&#8217;s still an interesting feature. And I&#8217;m really hoping as working on the WordPress developer blog that we kind of cut out the step where we do everything in Google Docs, do all the comments there. And then once everybody kind of has their word and say to move it and that we actually start creating the post in the blog and then just do the reviews from there. The only caveat is that to review and help, you have to be a member of the blog. You have to be an editor of the blog. But I think everybody who&#8217;s writing and reviewing either will be on the blog or will in the future or already has written a blog post. So they should be able to do it. </p>\n\n\n\n<p class=\"wp-block-paragraph\">Right now it&#8217;s only me doing it. Yeah, I publish in January and in February a post and it&#8217;s only me doing it. But it&#8217;s interesting to do this via notes. Yeah, because you get emails and all of that. Yeah, already. So it&#8217;s a good feature. The real-time collaboration, I haven&#8217;t done anything on that yet because it just came out. Yeah. So it&#8217;s not yet implemented. Anything else about real-time collaboration? Oh yeah. At the moment, and that&#8217;s with Beta 2, it&#8217;s a setting that you can opt into. So you have to go to settings. Writing, and I think the fourth from the top is the enable collaborative editing or real-time collaboration. Otherwise it wouldn&#8217;t work. I think for later versions it will be an opt-out, but it will be on the same space.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Where do you put this? I&#8217;ve just opened up the preferences. I have a test site which I spin this one up.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: But you go to the admin settings, the normal settings for writing.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Ah, the normal setting. Okay. I was in the editor, so that&#8217;s probably why I&#8217;m not seeing it there.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah. It&#8217;s not in the preferences. It&#8217;s in the admin dashboard and then settings and then writing.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Writing. Yeah. Oh yeah. There it is. Enable real-time collaboration. Let&#8217;s just try this out, how it looks like.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: I mean, I&#8217;m curious to see.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: You don&#8217;t see it when, when you are alone, all alone.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Well, I could create a second user and then just—</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah, and switch over in the second browser.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Switch over in another browser or another incognito tab.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: I think it could be in a different browser window. I tested it with Firefox and Google just to kind of not get into the way of each other.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Yeah, you need a different browser tab in the same browser. It&#8217;s not going to work because then you&#8217;re logged in with the same user, so you need to be logged in with two different users in order to make that happen.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: So it&#8217;s either an incognito window in the same browser or a different browser.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack: </em>Basically, you log in as admin, but you can switch the user over. There&#8217;s a user switching plugin. That&#8217;s what I&#8217;m using by John Blackburn. He has a very easy user switching plugin, and I&#8217;ll share the plugin link in the show notes. But then you can switch over to a different user. And then because I uploaded two avatars, so I can see the difference and all that. In the same note, another big feature, it&#8217;s not a new feature, but it&#8217;s a total revamp, is the visual revisions.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Oh yeah. Yeah. This is a big change. I&#8217;ve, I&#8217;ve tested this out before we started because I was really curious to see and Yeah, this is no more text walls and complicated HTML tags to understand and everything like before. I mean, I think the old one does have an advantage for like someone like me who&#8217;s used to looking at code all day and I can get my way around it. But I guess for many people who are not this, do not have an eye for this, this is like a massive wall of text and some green and some red stuff flying around somewhere. So I found it a very interesting way to create the revisions, to visualize the changes. I mean, I only made minimal changes to a page, like adding a paragraph, removing, removing a sentence and whatnot. But yeah, it&#8217;s actually kind of interesting.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: So one of the major features is it&#8217;s in the editor. You don&#8217;t have to switch screens to see your revisions. That&#8217;s also a plus. It knows what blocks are. So every change is filled in red and green. Red when you remove something, green when you add something. And it has a little banner on the right-hand side to outline.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: To indicate where on the page about where. I mean, I only had a short page, so it wasn&#8217;t that big of a deal, but it kind of, I think it really showed where it was. Like if there&#8217;s a specific paragraph you&#8217;re looking at, then let me just open up this.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah, it&#8217;s really nice. Ella did a fabulous job on that.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: And there&#8217;s also not just red and green, but there&#8217;s also yellow if something inside a paragraph changes that is not like completely adding or I think I know for this one, I added something inside an existing block. So the block itself is outlined in yellow. Hey, something changed here. And then the part where I added the words that is highlighted in green. So it&#8217;s like also kind of detailed and not just red and green like before, but you have also yellow, which indicates some sort of change, maybe with either an additional removal.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah. Yeah. It&#8217;s really nice. It&#8217;s very visual and staying in the block editor is such a relief. You don&#8217;t have to go back and forth and you have on the top of the screen. You also have the different versions of things. So you can, it&#8217;s a slider with the dates attached. So you can kind of, and the publish button changes to a restore button. So you can select the version that you wanna restore here.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: And you can also exit there. So it&#8217;s like you do not have the editing ability anymore. So the entire editing ability is stripped from that page. And instead you have either restore or exit. So I think this makes it distraction-free. So it&#8217;s also good because then people will not start editing inside that. It&#8217;s just a visual representation of things that have changed.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Exactly. Yeah. Good. And then do you want to take the next feature or?</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: I have not. I have seen this. So I was curious to see because I saw something else down in the Gutenberg 22.6 Release notes, if you will. But I saw that when you&#8217;re trying to hide any block, you can now hide them specifically either on desktop, tablet, or mobile. So it&#8217;s not just on or off, but you can now, in WordPress core without any extra plugins, say this either show only on desktop, show only on tablet, show only on mobile. The little downside here is that if I&#8217;m not mistaken, you can still not change the ranges of the viewports. You can?</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: No, no, that&#8217;s still hard-coded. </p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Exactly. So you&#8217;re still tied to the default states of what is desktop, what is tablet, what is mobile. So that is the little downside, if I say so, because oftentimes, at least in my experience, people want to really hone in. I want mobile to go to up until this specific size and tablet to be in this range. And they often differ from what WordPress offers by default. So that&#8217;s why many plugins have been popular in the past and many different integrations are there. So I think it&#8217;s important to mention that it does work. I guess it does work because otherwise it wouldn&#8217;t be in the Beta version, but it is restricted to what core says about the viewports.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: So yeah, yeah. And it&#8217;s a, it&#8217;s a range. It&#8217;s mobile starts at 480 and desktop starts at 768 and in between is the tablet. So I have found that I cannot make my browser window small enough to see the mobile version, but that&#8217;s, I think, a setting on my desktop. I&#8217;m not quite sure, but if you use the developer tools, you can see it or the previews, of course. Yeah, the preview inside the block editor will show you yes or no. With 20.6, they also added a feature for the list view where you see the eye for visible or invisible. It also has a little tooltip saying, okay, it&#8217;s visible on desktop or it&#8217;s visible on mobile and hidden on tablet and these kind of things. So there&#8217;s a little bit more visual support for figuring out why is that block not working. Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Yeah, that&#8217;s true. Yeah, it seems to work pretty well. So I just played around with it and put a paragraph to hide on desktop. It does no longer show at desktop, but once I make the browser smaller, it appears again. So seems to be working pretty well.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah. Yeah, the next feature is, well, it&#8217;s kind of a set of features for the navigation block. That has been coming in. There are a few things that are making navigation easier. One is that you now have control for your hamburger menus, your mobile hamburger menus, or if you want them on desktop too. Yeah. So you can now create different overlays for your navigation. And 7.0 will come with a few patterns. So you don&#8217;t have to do the whole creative work. You can just kind of say, okay, I will use this one and this one. It&#8217;s on the basis of template parts, so it can be reused on other places and templates if you have different overlays. And so I really like that.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Yeah, it gives more customization that wasn&#8217;t there before because you just only had a mobile version of the navigation you created. And I know from our experience at Grade that people like to switch up things in this mobile view because they want to add a button or add information or whatever, or change the menu items by default to have less menu items than they would have on desktop. So this was only possible with other tools, and now it&#8217;s in core as well. I also played around with it a bit, just adding random blocks to it. So it&#8217;s not just limited to specifically a navigation, but can add anything you need into that because it&#8217;s a template part, as you said.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: So yeah, right.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: So it actually is then also possible to create mega menus, which is also something that a lot of people wanted to do with those template parts.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Well, I haven&#8217;t played with, played it that far so far. I haven&#8217;t looked at the settings in detail, but. I guess I have to test this out.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah. Well, there are a lot of people who are going to be testing things and I wish they would share a little bit more about their successes or, well, they never really talk about their successes, mostly about, oh, this is a bug that needs to change kind of thing. But it would be really cool to see some other implementations. Yeah. </p>\n\n\n\n<p class=\"wp-block-paragraph\">They also revamped the submenus a little bit with handling that. So it now defaults to open or closed states, and you have a place to put the close button for that. Yeah, the patterns we talked— the overlay patterns is kind of with a black background, with an orange background, with a side info as well. So it&#8217;s pretty cool. Oh yeah, and what also changed in the navigation is that you can now— well, you always could add new pages when you create a navigation bar, create a new page, but now you can, you have a toggle switch that you can actually publish it. So the create a page is then available in your pages, but the menu works. And they did also a fantastic job making the links in the menu a little bit more smart. Yeah. So when you change the title or the slug of a page, it now reflects in the menu where it&#8217;s actually used. So that is, was also a big big pain point that you always had to think about, oh, I changed the slug of my page or my post. Now I need to update two menu items because I have a header, a footer, a header menu and a footer menu. And yeah, it&#8217;s all kind of a, it was a little bit.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Or another five menus in different places that you all need to update and you forgot about them. So yeah, that&#8217;s actually very nice. I just opened up also the, when you have a navigation block focused and go select one of the pages that is in there. It now shows a little, I&#8217;m not sure how long this has been there, but there&#8217;s a box popping out saying the title of the link and then it links to this specific page, which is a page. So the post type is shown and also what status it has. So it is published, is it draft or whatever. So there&#8217;s, I think if I click on that, yeah, I can now go directly into editing and I can go back. Oh, this is fancy.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah. Yeah. That&#8217;s also fairly new. I think it was in 22. So it&#8217;s between 6.9 and 7.0. It&#8217;s a new feature. It&#8217;s a new feature.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Yeah. I think this will definitely enhance the whole working with navigation, with navigation in general, because to be honest, it has been a pain to work with navigation. So I&#8217;m glad to see some improvements here. They&#8217;re looking really good. Oh, you can even add more stuff, description and real attribute. Nice. That&#8217;s looking good. I like that. I honestly like that.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Awesome. Very good, Birgit. What&#8217;s next on the list?</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Next on the list is gallery block add lightbox support.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Ooh, that&#8217;s my personal favorite. Yeah. Well, lightbox support was there before, right?</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: I was just saying that the lightbox has been around for a while. But yeah, not only for images, right? Not for the gallery.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: It was for the gallery, but it only added the click to open big. It wasn&#8217;t a real lightbox. It kind of— you needed to close it and then look at the next picture and open it up again. And now you actually have navigation with next and previous, so you could actually have a really nice gallery viewing experience. And I was waiting for this for quite a while. Not that I didn&#8217;t find any plugins that do that, but yeah, to have it in the browser.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: I think that&#8217;s a very nice feature because it reduces the need for a plugin if the functionality is enough for the user. I mean, there will always be plugins that enhance this functionality or create another variation of a lightbox with even more features. There&#8217;s always like that, but it&#8217;s, it&#8217;s good to have that because it&#8217;s just, I&#8217;ve never really worked so much with galleries in the past, but probably I will do more because now you can continue switching to the other images without even having to close that. So I think that&#8217;s really a good quality of life improvement.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Absolutely. Absolutely. Yeah. Yeah. Those sites that have big visual assets on there, like pictures and they have portfolios or they want to show a decoration or be it food. Yeah. Each one of the sites. And what I like about it is also that you can swipe it on mobile. You don&#8217;t need to—</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Oh, nice.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: It&#8217;s not animated, but it&#8217;s definitely there. </p>\n\n\n\n<p class=\"wp-block-paragraph\">So the thing that moved to the next version in WordPress is showing the captions somewhere on that. Yeah. Right now it&#8217;s just a picture and the navigation, but that&#8217;s a huge step forward. What also is new for the gallery block and many blocks is that the sidebar where the settings and the styles are now also have a content tab where you can see, for instance, all the pictures in a list and then just open it up and add an alt text to it, for instance. So you can have an easier way to update the content of things. You&#8217;ll see that also on other blocks that are kind of multi-blocks, like the social icons or the buttons or the list, that you get now a little content section on the right-hand side. And you don&#8217;t have to, for that, open up the list view. It&#8217;s a little bit of duplication, but I think it&#8217;s a different mindset when you just want to edit that particular group of blocks and see it in one view.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Yeah, but you can, I just created a gallery on my test site and picked some of the pictures. And when you are in this content section and you click on an image, you are put to the specific image block within the gallery. So I don&#8217;t think this is too much of a crazy thing. Yeah, you are right about the duplication that if you are on the gallery block itself, you can add something. That&#8217;s probably easier on the right side now to add something. But you also get the context options that you would have in the list view. So this is the duplicated part. But to be honest, I mean, I work a lot with the list view. I always— the first thing I do when I come into a brand new editor is go to preferences and say, list view, always show list view. Because I still don&#8217;t get why this is not the default. But yeah, for people who may be not using the list view too much, I think this is a pretty nice way to work with the gallery block. Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: And there are also people who are overwhelmed by the list view. Yeah. So kind of, they don&#8217;t.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Yeah, I can understand. But yeah, I&#8217;m a big fan of the list view.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: So yeah, there will be two new blocks. There&#8217;s a breadcrumbs block and the icon block. And the icon block just made it out of experimental with 22.6. </p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: I think this was a very close call, right? I just saw Ryan&#8217;s post the other day. It&#8217;s like, we made it. And I was like, oh, that&#8217;s close. Isn&#8217;t Beta 1 already out yet?</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah, no, it was, uh, actually in Beta, but the discussion was about— not about the icon block per se, but it only has limited functionality. When you— for a designer, you cannot register your own icon collection.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: That would have been my question. Yes.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: And that has been the API that was too close to be comfortable in creating a new API at the last minute, so to speak. And they said that needs to be similar for a moment. And that was pushed in 7.1, but you still can use the icons that are in the block editor already.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: It mostly, it will be arrows or the chevrons or maybe something like pencil or image or home. Yeah. The default ones are there. So it&#8217;s, I would say for, for the, for the beginning, it&#8217;s fine. And I think for the extensibility, it&#8217;s definitely needed that we have an API to add any kind of icon that we want or that the user needs because people work with the most different things. I think the same, we had the same thing with the social icons block, if I remember correctly, like you had a fixed set, but then later on. It was added the ability that you can upload your own icons, if I&#8217;m correct.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: So I would very much look forward to potentially in 7.1 that we get the ability to extend this icon library to whatever icons we need, have an upload.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah. Yeah. I think designers really work, love working with icons and when they design sites, it would be really helpful to actually have the branded icons, whatever they have to be uploaded. But yeah, in the release post of 22.6, Bernie Reiter, who was a release lead, he uploaded an implementation which makes perfect sense, which is the location for a map, kind of, yeah, what&#8217;s the address, what&#8217;s the link for Google Maps, and what are the ratings, so to speak. And you can all do that with the icon set that&#8217;s already in the block editor. It was worth it, even with not registering the API, to put that into a core. And it&#8217;s still helpful.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: I mean, the icon block has been long awaited, so it was about time.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah. And the other block is the breadcrumbs block, which I&#8217;m really happy that it made it because that&#8217;s a very versatile block. It has a lot of smartness behind it where you can put it on any page and then it figures out what are the breadcrumbs to get to that page and also to get back again. So you could do categories, archives, subpages, parent pages, child pages. It&#8217;s all picking up those things. And it&#8217;s a really nice addition for larger websites to have a user find their way back or orient themselves on the website.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Yeah, I think there&#8217;s also enough settings to work with it. So it&#8217;s looking good. I just added it to my test page. You have all the color, typography, dimensions, border. So there&#8217;s, there&#8217;s something to do with it. I would say.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah, you can definitely work with that. So then the existing blocks obviously also get some improvements. Do you have any favorite of those? I do. So the paragraph has two new things. One is the indentation. So you can make a paragraph or on a page manage the indentation of the first line in a paragraph. There are two versions of it that you need to handle in the settings page. One is to have the first paragraph not indented, but all the subsequent paragraphs. And then if you toggle that off, then also the first paragraph is indented. And that is that it&#8217;s in the English-speaking countries, the first paragraph is not indented. But in the right-to-left and other countries, even if they are left-to-right, they always want all the paragraphs indented. So it&#8217;s a different standard for publications in different countries. So they needed to take care of that. But the default is to have the first paragraph not indented and all the subsequent paragraphs are.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Interesting.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: It&#8217;s like I usually do not come around that the need for this. But obviously if there&#8217;s a need for it.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah. A lot of publications have that as standard, especially those that are in the news and long-form content publications like essays and that kind of thing.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Apparently I do not read those, so I do not have any experience with that.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Or you just haven&#8217;t noticed it because it feels natural.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: But probably, yeah, yeah, I maybe, maybe that&#8217;s also the case. I don&#8217;t know. Yeah, but it&#8217;s interesting to see that. I was wondering, didn&#8217;t we have something like this before, or was it something else, or I&#8217;m mixing this up with something? I don&#8217;t know.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah. And the second formatting part for paragraph block is that automatic text columns. So you can have a larger paragraph and say, okay, but I need this into a smaller space, but I have multiple columns. And that also works very well. That was actually a plugin from the Block Editor Learn program. There was one course that actually created that kind of columns. So I&#8217;m glad that it made it to core because I really found it nice to have that possible. It automatically creates those columns. You can say 2 columns or 3 columns, and it&#8217;s really nice. You need to enable it through the typography, the 3-dot menu. </p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: I was just about to say, I&#8217;m not seeing the setting. Where is it? Ah, here it is. Columns.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah, yeah, columns. And also the indentation. And that&#8217;s also where you&#8217;ll find the fit the text into that. So there are typography changes, but right now only, I think, available for the paragraph block.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Yeah, it made sense to have moved to the tools panel to get a bit more in the technical side, because if I&#8217;m looking now at the typography settings that are available, but this list is like endless. Yeah, it&#8217;s getting endless. So having this to be hidden by default and you can, if you need the to change something, you edit. That&#8217;s something, yeah, definitely to not clutter the sidebar too much.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: So yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Yeah. Yeah. It&#8217;s a good call to always look at the three dots in the menu to see, okay, what other options do I have available there? Because they may not be visible just, and you look stupid like I did to find the columns.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: You look not that stupid.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Yeah, it&#8217;s just like, well, why, why I&#8217;m not seeing this? Where is this? Is this a setting somewhere? It&#8217;s like panicking on the inside on the podcast. I know it&#8217;s, it&#8217;s like day-to-day business.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: So yeah, I&#8217;m all good. So what else is in the current block? There are so many things in there. So the font library has now its own menu item in the appearance menu. Yeah. Nothing else.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: So it&#8217;s available for any themes if I recall correctly.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: So it&#8217;s not—</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: you can now do all the stuff. Yeah, it&#8217;s exactly the same like the modal. You just have it like as in the regular backend, basically. It&#8217;s been like extracted from the editor to be its own backend page.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: But it&#8217;s in the new style. I just realized that when switching between the default themes, we have the overview to switch the themes. It&#8217;s like still the we did get a little change in the backend. Maybe we can talk about that later. But when you are on themes, you have still this dark, not dark, but lighter gray, very light gray background. And it&#8217;s no rounded corners. And when you go into fonts, you have this more site editor-like white background and rounded corners around. I just realized that there&#8217;s this kind of difference.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah, I think that the team really wanted to do the data views. Use components from the data views for these new pages. And it will also be, and I just saw that for the Beta 2, that the connector for the AI client, that the connector page is under Settings. Yep. And the page also follows that data view.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Correct.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Design from what&#8217;s actually going to be the new admin design that&#8217;s not coming to 7.0, but some of the pages are, look a little bit different yet. Now.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: I just see, I just see these small details like instantly. So I was like, oh, this looks different.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah. Yeah. It looks a little bit fresher. It&#8217;s my personal view on that.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: And I, I think the most visual change everyone will have is when they log in. So, or when they upgrade to 7.0 and they have not seen the Beta or release candidate that suddenly the default color scheme changes. In the backend. So I think this will be a bit of a woo moment for everyone who is not like looking into this before. So if I guess it&#8217;s a shout out to everyone who&#8217;s working with clients who do not see a Beta version before, be prepared because I&#8217;m sure there will be questions coming in from everyone like, my admin looks different. What happened?</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah, the buttons all have a different color. Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Yeah, the, the, I think the black is a bit darker if I remember correctly. And of course the blue shines very differently. Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: So, but the color scheme was available before. It&#8217;s called the modern.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Yes, correctly.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah. So it&#8217;s now just the default. I don&#8217;t think we have materialized any writing about that. So I kind of need to look at the core changes. Right now I&#8217;m just looking at the block changes, but yeah. Oh, and one thing that we should mention is the content-only pattern editing that&#8217;s now coming with 7.0. And that is a way, if you have a pattern that you put into a post or a page, that the edit the pattern is kind of reduced to edit the content of it. So you don&#8217;t have to change the pattern. Yeah. And I think that&#8217;s reducing a little bit the overwhelm. And the danger that people get into when they just use pattern, that they are kind of, you still can edit them, throw out the image and put a different block in there. You always can, you can change the headline, paragraph, whatever the pattern is designating as content only. Blocks, patterns, headlines, paragraphs, lists, buttons, those can all be just added, just change the content of it. But there is an edit button on the right edit pattern, and it&#8217;s for unsynced patterns as well as for sync patterns. The sync patterns has a different workflow when you change the original. That was always in there, but now this is coming to the unsynced patterns as well. When there are multiple patterns in multiple blocks in a pattern. So they&#8217;re kind of designated a section and then you can reduce the trouble a content editor can get themselves into.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: I see. I see. Yeah, it certainly looks different. Yeah, you have different buttons. But yeah, you cannot go into like— yeah, you can like make it bold or italic or any of the work with the text. But yeah, you cannot say I want the button color to change. Is this the default for all patterns? As you said, it&#8217;s like I&#8217;ve now just added a regular pattern. And it&#8217;s not synced. So I assume it&#8217;s not synced.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Let me check.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: I think so. Interesting. So when I go to edit pattern, oh, I now have to go to edit pattern in the toolbar. In the sidebar. I have now edit pattern.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: No, no, in the block toolbar.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: That&#8217;s the block toolbar. You can say edit pattern and then you get all the controls for each block to move them, delete them, whatever. And then you can go back and then you have, when you are in the pattern, you have only the editing ability as you described. So you can, cannot change the blocks itself, but you can like change the contents. I can change the image and set an alternative text, but I cannot say, give it a different aspect ratio or use a different image size or whatever.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Or make the paragraph a list or something like that. There, those decisions.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: So this is actually very good to know because I just stumbled upon that and, ooh, this will be why I wanted to do this. This will be interesting because that&#8217;s like, that&#8217;s a huge change. I can see the struggle people will have who are not aware of this to get into the editor. They have added a pattern, simply a pattern, and now they want to change the heading. For example, and now on 7.0, they&#8217;re like, the possibility to change the heading is gone. And they do not realize that they have to click on the edit pattern block first in order to change the heading level, for example. So I think this could be from the user experience part.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah, a little bit of a stumble block. Yeah, absolutely. The dev note, and I see, I saw the draft of this dev note for that. There&#8217;s also a way for site admins to opt out of content-only. That especially if you are working with clients or you&#8217;re creating themes, you probably want to, because you want to edit the pattern all the time. You can opt out of it with a filter. And both are available for PHP as well as for JavaScript. And as a plugin developer or theme developer, you can designate patterns as content-only. And with an attribute in the pattern. Block thing. Those who create custom blocks, they can also designate in the block JSON which attributes are content only. You give it a role equals content in the block JSON. So there are multiple ways to kind of skin that cat, as they say in America. So for the end user, I think the advantage is that there is no ambiguity if I change that. Is that getting me into trouble or something like that? Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Yeah. Yeah. From that point of view, I&#8217;m coming from a different point of view where the user is used to working with that and suddenly they cannot on the first glance, they cannot edit stuff anymore. Like they cannot change the heading level or font, font size, font, font family, whatever. So I think from that perspective, this will be a bit of a struggle.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: So yeah. But I think the edit pattern button is prominent enough in the sidebar. But yeah, we&#8217;ll kind of need to see what the verdict is about that.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Yeah, yeah, true, true. So this will be an interesting thing to catch on, especially if you&#8217;re a heavy pattern user. This will be very interesting.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah, I think the—</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik: </em>I mean, I do see, I do see, don&#8217;t get me wrong, I do see the point in like having this content only. I mean, we have something very similar in our Grid plugin. Where you can lock down, like you have the structure, but you can only edit the content. It&#8217;s very, very similar. So there is the need for this. It&#8217;s just like coming when you are already working with WordPress and then you&#8217;re coming to this. That is the issue that I&#8217;m seeing. So, but for real, for real, the, yeah, for real, the, this reduction of overwhelm to, oh my God, I have so many options, but the pattern is there, but you cannot break it.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Mm-hmm.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Uh, totally. That&#8217;s totally a cool thing.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah. And I get your point, but what is it? It&#8217;s a 30-second, oh, I need to click on edit pattern. Uh, kind of reveal of that. Yeah. It&#8217;s not a kind of totally, oh, I, I get your point.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Well, if, if you are lucky, if you are lucky and the people see it and have the, I do not want to sound, uh, too, too negative about it, but if they have the curiosity to like explore. To do like, okay, what happens if I click on edit pattern? But you also have those people like who are like literally overwhelmed already by this and then go to whatever support people you have, whether it&#8217;s a plugin, a specific plugin is, I do see an increase of people coming into our support, for example, and saying, hey, things are not working anymore because of, I don&#8217;t know what&#8217;s happening here.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: So, yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah. So I get that, especially because people just go into the website to get something done. And if they are overwhelmed with all the changes, it&#8217;s kind of a certain whoops.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: I didn&#8217;t expect that to change on me forever. Yeah. I totally get it.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: If they just want to add a text, they will probably not notice or maybe realize, okay, something is different. But as soon as they want to change anything that is related to the blog, I think then it&#8217;s when it&#8217;s going to be—</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: just to the design. Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Absolutely. Yeah. Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah, exactly.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: So I think the last thing that we talk about a little bit here is what did not make it into the 7.0. That was on the roadmap. And that was the playlist block didn&#8217;t finish in time. The dialog block, which I really like. The dialog block is something that you get a button or a link and then you can control what dialog comes up for that. And the tabs block that I&#8217;m really sad about that it did not make it.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Do you know what happened to like why the decision was made to not bring it in?</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: They have some, there was an aspect of the active tab state in a non-standard way. There were some accessibility issues that they kind of wanted to revisit.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Oh yeah. Tell me about it. Tell me about it. I made the Tabs plugin, the great plugin accessible. So it&#8217;s possible. So, but yeah, I get that this may be the reason why it has been cut out.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: I think there were too many people, too many cooks in the kitchen for that with different changes. So I think they need to be finalized as well. And then the playlist block. I&#8217;m really sad about that, but we will see. And then some of the notes features that were thought about didn&#8217;t make it either. There were a few things that haven&#8217;t been worked on that were in the roadmap, were kind of, kind of was aspirational, but it wasn&#8217;t really prioritized. So like there were short blocks. A lot of people would like to see that. That&#8217;s like block binding, but inside the paragraph. So you can change dynamic data in a paragraph and just in, in a certain way. It could be a date or could be a change like the time zone change, yeah, depending on something. Or data from the meta fields, custom fields that are just in the flow text kind of, you want to put them in. I know that people work on that. Slider block was not worked on and some of the media things. Didn&#8217;t make it either. So are you excited about WordPress 7.0? </p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: I mean, there&#8217;s a lot of very interesting changes and I mean, just because something didn&#8217;t make it, I think there&#8217;s a lot that made it that is already giving an impact. We haven&#8217;t even touched the AI part. So I think this is also something that is really coming. And even that in itself is probably enough to make another episode about if you want to. Yeah. </p>\n\n\n\n<p class=\"wp-block-paragraph\">But overall, I think there&#8217;s some good quality of life improvements. I mean, real-time collaboration is something that everyone has to look for themselves if it&#8217;s useful. I can see it useful, of course, in like Google Docs style if you need to collaborate really on something, but also in support essentially to like, okay, let me get into the same page and show me on a video call what are you doing, or without even being on a video call, without screen sharing, to see what the other person is doing essentially. I&#8217;m not sure if I think you can only see the editing sort of things, but overall to see, okay, I do this, I do that, and then this happens. I don&#8217;t know. This could maybe be a thing. Maybe we get the icon block, long, long awaited. We do have some more responsive hiding features, if you will. It&#8217;s, how to say, rudimentary, but it&#8217;s like, it works. So if you&#8217;re fine with that, then you&#8217;re good. Font library available to everyone. I think that&#8217;s not bad either. So yeah, I think overall this will be an interesting, an interesting release to have available.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: And I mean, there&#8217;s always work to do, so we&#8217;re not running out of work. You know, no, even if, uh, with the help of AI, I think the work is always going to be there. So for the developers amongst us, I think you want to look at the PHP-only registration for blocks. Also, some of the data view package changes for your own plugin might be very interesting for you. </p>\n\n\n\n<h3 class=\"wp-block-heading\">Gutenberg 22.5 RC</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Also, the client-side media improvements, they are there, but it&#8217;s not visible to anybody. It&#8217;s just kind of that the browser is now doing all the changes to the image, the downsizing for smaller aspect ratios or sizes. Yeah, it is done in the browser and doesn&#8217;t have to go to server and back. But that&#8217;s all relatively invisible to a normal user. True. I would come to an end here. We are almost at the hour and it was so much stuff to talk about. So is there anything, Jessica, that you want our listeners to know and you didn&#8217;t get a chance to talk about?</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Not really. Go testing, I would say. Make sure if you have a product like us, make sure things work so you do not get in too much trouble. There will always be people coming to you saying, hey, something does not work. I mean, we do have that too. It&#8217;s like, then it&#8217;s just simply helping people with WordPress that is not related to the product itself. But yeah, overall, just make sure things work because like there are some changes happening. We also didn&#8217;t touch too much on the iframe editor situation in our chat. So I think this is something you should look into. I think there has been a new post by Ella this week with some more information. So yeah, for the developers of us, take a look at that because I think that maybe can potentially cause issues.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: It shouldn&#8217;t, but yeah. And I&#8217;m kind of hard to think about a scenario how we could test this with older plugins because I don&#8217;t see sites that are in with maintenance with a developer, so they probably won&#8217;t have a problem. They&#8217;re already kind of up there because the Gutenberg plugin has always already been updated with the iframe. So, I&#8217;m looking at people who haven&#8217;t updated their site for 5 years or something like that with the old blocks version in there. And all of a sudden they come back, but they, the front end won&#8217;t change. So they wouldn&#8217;t see it unless they go in, in the editor. And I have not seen yet something that fails. So that&#8217;s why it&#8217;s now in the Gutenberg plugin. That the post editor is loaded in the iframe.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Yeah, it will not be enforced in 7.0, but on the horizon we already see, okay, if it&#8217;s now in Gutenberg 22.6, potentially we will have to deal with it in 7.1. So this summer around that time. Yeah, I think that&#8217;s, that&#8217;s something important to, to just have in the back of your mind that if you have a product or if you have not just a product, but also like, like you said, created custom blocks for a client for specific websites. And there is like either no maintenance or very low maintenance contract, then you need to be aware that things can change, will change. And we had these discussions in the past. I have to say that there are people who were very frustrated that things have changed in the editor and made actually their frontend go sideways and not too bad, but like, okay, wasn&#8217;t looking as it was before. So I can totally understand that frustration, but, I mean, it&#8217;s software. It&#8217;s a moving project. It&#8217;s never going to be this forever unless you lock in the default WordPress version and only receive security updates, then well, okay, you can deal with that.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: But yeah. Yeah. But I don&#8217;t think that this block iframe or block editor iframe thing for post edits, this is really a major change or breaking change. That, yeah, it, I don&#8217;t think that most WordPress users would even know that that happened or haven&#8217;t even noticed that it&#8217;s already happening. So for those who do client-side that are a little older, yeah, keep an eye out and let us know or let the contributors know if it&#8217;s breaking, what is breaking, so it can be dealt with for the next iteration on it. All right. </p>\n\n\n\n<p class=\"wp-block-paragraph\">And I also share in the show notes, the latest conversations that Grade and Jessica had with two agency owners about the block editor and FSE. I think that&#8217;s pretty insightful.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Oh, that was with the Codable Experts. Yeah, it was not the agency owners, but the Codable Experts.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Birgit Pauli-Haack</em>: Yeah. Yeah. Codable is an agency that matches up projects with freelancers and they have a very strict screening method for the freelancers. So they are real experts and they know what they&#8217;re doing and so, thank you for telling me that. Anyway, so I will share that. So if anybody who wants to listen some more, it&#8217;s on YouTube and it was Jessica. </p>\n\n\n\n<p class=\"wp-block-paragraph\">So, and as always, the show notes will be published on <a href=\"http://gutenbergtimes.com/podcast\">gutenbergtimes.com/podcast</a>. This is episode 127. And if you have questions and suggestions or news you want us to include, send them to <a href=\"mailto:changelog@gutenbergtimes.com\">changelog@gutenbergtimes.com</a>. That&#8217;s <a href=\"mailto:changelog@gutenbergtimes.com\">changelog@gutenbergtimes.com</a>. And thank you so much for spending this time with me and Jessica and going over the WordPress 7.0 features with me. And it was good to see you and talk to you. Thanks for listening and goodbye.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Jessica Lyschik</em>: Thanks for having me. Bye.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sun, 01 Mar 2026 17:15:04 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:19:\"Gutenberg Changelog\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:37;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:108:\"Gutenberg Times: Help test WordPress 7.0 beta2, CSS in Block themes, AI experiements – Weekend Edition 359\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://gutenbergtimes.com/?p=44470\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:113:\"https://gutenbergtimes.com/help-test-wordpress-7-0-beta2-css-in-block-themes-ai-experiements-weekend-edition-359/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:24645:\"<p class=\"wp-block-paragraph\">Happy Saturday! </p>\n\n\n\n<p class=\"wp-block-paragraph\">It&#8217;s been another interesting week in WordPress, Gutenberg and AI. </p>\n\n\n\n<p class=\"wp-block-paragraph\">If you would like to know more about my two weeks in New York and the immersive AI training there, here is a post for you. <a href=\"https://automattic.com/2026/02/25/ai-enablement-wordpress/\">What Automattic’s AI Enablement Training Means for WordPress</a>. </p>\n\n\n\n<p class=\"wp-block-paragraph\">And now, enjoy all the videos, blog posts and podcasts below.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Yours, <img alt=\"💕\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/1f495.png\" style=\"height: 1em;\" /><br /><em>Birgit</em></p>\n\n\n\n\n\n<h2 class=\"wp-block-heading\" id=\"0-word-press-release-information\">Developing Gutenberg and WordPress</h2>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress <strong><a href=\"https://wordpress.org/news/2026/02/wordpress-7-0-beta-2/\">7.0 Beta2</a> </strong>is now available for testing. How? Glad you asked. The Test team has compiled a great list in their post <a href=\"https://make.wordpress.org/test/2026/02/20/help-test-wordpress-7-0/\"><strong>Help Test WordPress 7.0</strong></a>. It&#8217;s the perfect way to learn what&#8217;s in the new release and you can help find bugs, that could be squashed before the final release.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Ray Morey</strong>, editor of The Repository, has some details in <a href=\"https://www.therepository.email/wordpress-7-0-beta-2-ships-with-connectors-ui-delivering-on-mullenwegs-ai-vision\" rel=\"noreferrer noopener\" target=\"_blank\"><strong>WordPress 7.0 Beta 2 Ships With Connectors UI, Delivering on Mullenweg’s AI Vision</strong></a></p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Ella Van Durpe</strong> shares <a href=\"https://make.wordpress.org/core/2026/02/24/iframed-editor-changes-in-wordpress-7-0/\"><strong>what&#8217;s shifting with the iframed post editor in WordPress 7.0</strong></a>: instead of checking all registered blocks across your plugins, WordPress will now only look at blocks actually inserted in the post. If they&#8217;re all Block API version 3 or higher, you get the iframe — if not, it steps back gracefully. Full enforcement isn&#8217;t happening in 7.0, but <em>Gutenberg plugin 22.6</em> enforces it for classic themes to gather real-world feedback first.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\">Release lead <strong>Bernie Reiter,</strong> published a new version, Gutenberg 22.6 and in his release post <a href=\"https://make.wordpress.org/core/2026/02/25/whats-new-in-gutenberg-22-6-25-february/\"><strong>What’s new in Gutenberg 22.6? (25 February)</strong></a> he highlighted:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://make.wordpress.org/core/2026/02/25/whats-new-in-gutenberg-22-6-25-february/#in-editor-revisions-visual-change-tracking\">In-Editor Revisions: Visual Change Tracking</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2026/02/25/whats-new-in-gutenberg-22-6-25-february/#icon-block\">Icon Block</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2026/02/25/whats-new-in-gutenberg-22-6-25-february/#navigation-overlay\">Navigation Overlay</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2026/02/25/whats-new-in-gutenberg-22-6-25-february/#client-side-media-processing\">Client-Side Media Processing</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2026/02/25/whats-new-in-gutenberg-22-6-25-february/#real-time-collaboration\">Real-Time Collaboration</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2026/02/25/whats-new-in-gutenberg-22-6-25-february/#gallery-lightbox-navigation\">Gallery Lightbox Navigation</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2026/02/25/whats-new-in-gutenberg-22-6-25-february/#other-notable-highlights\">Other Notable Highlights</a></li>\n</ul>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Anne McCarthy</strong> shares a candid look at <a href=\"https://nomad.blog/2026/02/28/iterating-on-notes-in-wordpress/\"><strong>iterating on Notes features in WordPress</strong></a> that didn&#8217;t quite make the 7.0 cut. Built with Claude Code as part of her &#8220;Learn AI deeply&#8221; efforts, the three PRs in progress cover show/hide notes on the canvas, filter options (she leans toward &#8220;Open&#8221; over &#8220;Unresolved&#8221;), and compact note display. Questions around a resizable sidebar and UX friction remain open — your feedback on the PRs is warmly welcomed.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Jessica Lyschik,</strong> senior developer at Greyd, and I had fun recording another Gutenberg Changelog episode. We discussed the main user-facing features coming to WordPress 7.0. </p>\n\n\n\n<div class=\"wp-block-group has-light-background-background-color has-background\"><div class=\"wp-block-group__inner-container is-layout-constrained wp-block-group-is-layout-constrained\">\n<p class=\"wp-block-paragraph\"><img alt=\"🎙\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/1f399.png\" style=\"height: 1em;\" /> The latest episode is <a href=\"https://gutenbergtimes.com/podcast/gutenberg-changelog-127-wordpress-7-0-beta/\">Gutenberg Changelog #127 – WordPress 7.0 Beta and Gutenberg 22.6</a> with special guest <strong>Jessica Lyschik</strong>, senior developer at Greyd</p>\n\n\n\n<figure class=\"wp-block-image size-full is-style-no-vertical-margin\"><img alt=\"Jessica Lyschik and Birgit Pauli-Haack recording Gutenberg changelog episode number 127\" class=\"wp-image-44548\" height=\"184\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2026/02/Screenshot-2026-02-27-at-12.47.56.png?resize=652%2C184&#038;ssl=1\" width=\"652\" /></figure>\n\n\n<div class=\"wp-block-newsletterglue-showhide ng-block\" width=\"100%\">\n<figure class=\"wp-block-embed is-type-rich is-provider-pocket-casts wp-block-embed-pocket-casts\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n</div></div></div>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"0-p\">Plugins, Themes, and Tools for #nocode site builders and owners</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Tom Finley</strong> introduces <a href=\"https://tomfinley.com/stop-rebuilding-wordpress-block-patterns-from-scratch-use-block-zapper/\"><strong>Block Zapper</strong></a>, a utility block that strips custom colors, spacing, typography, and backgrounds from WordPress block patterns in one click — so you can actually use them as clean starting points. You get granular control: preserve images and cover backgrounds while clearing everything else. Finley&#8217;s one important warning: it&#8217;s largely vibe-coded with AI assistance, so sandbox it thoroughly before touching any real project, and move your zapped blocks out before leaving the editor.</p>\n\n\n\n<p class=\"wp-block-paragraph\">This seems to be inline with the <strong>Content Only Pattern editing experience</strong>, core contributors also try to achieve abstracting away the design aspects of working with patterns for content creators. It&#8217;s about to come to WordPress in 7.0 (or 7.1, the jury is still out) It is already available in the Gutenberg plugin 22.6 and this <a href=\"https://github.com/WordPress/gutenberg/issues/73775#issuecomment-3930751877\">GitHub comment by Ramon Dodd.</a> </p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\">Carleton University&#8217;s <strong>Troy Chaplin</strong> built the <a href=\"https://wordpress.org/plugins/block-accessibility-checks/\"><strong>Block Accessibility Checks plugin</strong></a> to catch what the WordPress block editor won&#8217;t — out-of-order headings, missing image alt text, and other gaps that slip through unexpectedly. Chaplin joined Chris Reynolds, Pantheon, on this week&#8217;s <a href=\"https://www.youtube.com/live/mLsC2tDcdL8\">YouTube Livestream</a> for a walk-through of how the plugin validates your content in real time and flags issues before they reach your readers. A practical tool for anyone serious about making their content genuinely accessible to everyone.</p>\n\n\n<div class=\"wp-block-newsletterglue-showhide ng-block\" width=\"100%\">\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n</div>\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\">On WP Builds, <strong>Nathan Wrigley</strong> sits down with <strong>Ian Svoboda</strong>, a veteran of 10up, GenerateBlocks, and GeneratePress, to unpack the<a href=\"https://wpbuilds.com/2026/02/26/458-unpacking-the-clever-content-area-block-with-ian-svoboda/\"> <strong>Content Area Block plugin</strong></a>. Born from a news site needing multiple editable regions per template, the plugin solves WordPress&#8217;s single-content-area limitation without meta field workarounds. You&#8217;ll hear about the technical hurdles — duplicating core hooks, navigating unstable APIs — and why this capability still hasn&#8217;t made it into Core.</p>\n\n\n<div class=\"wp-block-newsletterglue-showhide ng-block\" width=\"100%\">\n<figure class=\"wp-block-embed is-type-rich is-provider-pocket-casts wp-block-embed-pocket-casts\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n</div>\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Rodolfo Melogli</strong> is the organizer of the <a href=\"https://checkoutsummit.com/\">Checkout Summit in April</a> and editor of the <a href=\"https://wcwkly.com/\">WooWeekly</a> newsletters. In his recent blog post, he discusses <a href=\"https://www.businessbloomer.com/my-honest-take-on-woocommerce-checkout-block-adoption/\">WooCommerce Checkout Block adoption</a> and explains that most merchants still use the classic Shortcode even after two years of the block being the default option. The main issue is hesitation around plugin compatibility. Although WooCommerce data shows a 27% boost in conversions with the block checkout, the ecosystem has not fully adapted, and merchants are reluctant to risk disrupting their working stores.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"2-word-press-6-0-1-and-6-1-scheduled\">Theme Development for Full Site Editing and Blocks</h2>\n\n\n\n<p class=\"wp-block-paragraph\">If you&#8217;ve ever wondered where your custom CSS actually lives — or should live — this comprehensive guide on <a href=\"https://gutenbergtimes.com/14-ways-to-add-custom-css-in-wordpress-block-editor/\"><strong>14 ways to add custom CSS in the WordPress Block Editor</strong></a> is your new reference. Covering everything from <code>theme.json</code> structured properties and CSS variables to per-block Additional CSS, Block Style Variations, and <code>wp_enqueue_style()</code>, you&#8217;ll find a decision guide to match each method to your role, whether you&#8217;re a site builder, designer, or theme developer.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Jon Ang</strong>, Human Made, made the case that <a href=\"https://humanmade.com/wordpress-for-enterprise/how-wordpress-solves-visual-editing-without-the-complexity-tax/\"><strong>WordPress in 2026 escapes the complexity tax</strong></a> that headless and composable stacks imposed on enterprise teams. The Site Editor, combined with Synced Patterns, Block Bindings, and the Interactivity API, now forms a structured visual system that scales alongside enterprise design systems without forcing teams into heavyweight JavaScript frameworks or fragile third-party glue. As Ang put it, it becomes a system interface &#8220;where visual work is grounded in real content models&#8221;.</p>\n\n\n<div class=\"ng-block-7bd1b2537eb325c2 wp-block-newsletterglue-container ng-block\" style=\"color: #666666;\" width=\"100%\"><div><div><div class=\"ng-block-vs ng-block-vs-1\" colspan=\"3\" height=\"0\" style=\"height: 0px;\"></div></div><div><div class=\"ng-block-hs ng-block-hs-1\" height=\"0\" style=\"width: 0px;\"></div><div align=\"none\" class=\"ng-block-td\" style=\"font-size: 16px; font-family: Helvetica; line-height: 1.6; font-weight: normal; padding-top: 20px; padding-bottom: 20px; padding-left: 0px; padding-right: 0px; text-align: none; color: #666666; background-color: #fdfcea; border-radius: 12px;\"><div class=\"ng-block-1d8452a3e5c42923 wp-block-newsletterglue-text ng-block\" style=\"color: #666666;\" width=\"100%\"><div><div><div align=\"none\" class=\"ng-block-td\" style=\"font-size: 16px; font-family: Helvetica; line-height: 1.6; font-weight: normal; padding-top: 8px; padding-bottom: 10px; padding-left: 20px; padding-right: 20px; text-align: none; color: #666666;\"><p><strong> <a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/\" rel=\"noreferrer noopener\" target=\"_blank\">&#8220;Keeping up with Gutenberg &#8211; Index 2026&#8221;</a> </strong><br />A chronological list of the WordPress Make Blog posts from various teams involved in Gutenberg development: Design, Theme Review Team, Core Editor, Core JS, Core CSS, Test, and Meta team from Jan. 2024 on. Updated by yours truly. </p></div></div></div></div>\n\n<div class=\"ng-block-1aaa0c92b33523dd wp-block-newsletterglue-text ng-block\" style=\"color: #666666;\" width=\"100%\"><div><div><div align=\"none\" class=\"ng-block-td\" style=\"font-size: 16px; font-family: Helvetica; line-height: 1.6; font-weight: normal; padding-top: 8px; padding-bottom: 10px; padding-left: 20px; padding-right: 20px; text-align: none; color: #666666;\"><p>The previous years are also available: <br /><strong><strong><a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/keeping-up-with-gutenberg-index-2020/\">2020</a> | <a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/keeping-up-with-gutenberg-index-2021/\">2021</a></strong> | <strong><a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/keeping-up-with-gutenberg-index-2022/\">2022</a></strong></strong> | <strong><a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/gutenberg-index-2023\">2023</a></strong> | <a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/gutenberg-index-2024/\"><strong>2024</strong></a></p></div></div></div></div></div><div class=\"ng-block-hs ng-block-hs-2\" height=\"0\" style=\"width: 0px;\"></div></div><div><div class=\"ng-block-vs ng-block-vs-2\" colspan=\"3\" height=\"0\" style=\"height: 0px;\"></div></div></div></div>\n\n\n<h2 class=\"wp-block-heading\" id=\"3-building-themes-for-fse-and-word-press\">Building Blocks and Tools for the Block editor.</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Ryan Welcher</strong> released v. 1.0.3 of his VSCode extension <strong><a href=\"https://marketplace.visualstudio.com/items?itemName=ryanwelcher.wordpress-interactivity-api-helper\">WordPress Interactivity API Helper</a></strong> that adds autocomplete for directive and even detects items in your store. After you install it you can invoke it by &#8220;Simply start typing <code>data-</code> in any HTML attribute position within PHP or HTML files&#8221;.  </p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"Ryan Welcher\'s Interactivity API VSCode extension\" class=\"wp-image-44552\" height=\"318\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2026/02/interactivityAPI-VSCode-extension-1024x500.jpg?resize=652%2C318&#038;ssl=1\" width=\"652\" /></figure>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Ryan Welcher </strong>also released a new version of <a href=\"https://github.com/ryanwelcher/advanced-query-loop/releases/tag/4.4.0\"><strong>Advanced Query Loop 4.4.0</strong></a> that enhances query speed and reliability. It includes transient caching for AQL instances and a new management control, along with fixes and improvements to caching. The current post ID and type are now included in the context, and the release features expanded unit tests, E2E tests via Playground, and static linting for both PHP and JavaScript.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\"><strong>JuanMa Garrido</strong> walks you through <a href=\"https://developer.wordpress.org/news/2026/02/a-better-way-to-test-html-in-wordpress-with-assertequalhtml/\"><strong>the new <code>assertEqualHTML()</code> assertion introduced in WordPress 6.9</strong></a>, available on <code>WP_UnitTestCase</code>. If fragile PHPUnit tests that break over attribute ordering or style whitespace are your nemesis, this is your fix. It compares HTML semantically — not literally — so your tests only fail when markup is genuinely different. Covers block render callbacks, HTML API transformations, Interactivity API directives, and tips for migrating away from <code>assertSame()</code>. </p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"ai-and-wordpress\">AI and WordPress </h2>\n\n\n\n<p class=\"wp-block-paragraph\">In his post on The Repository, <strong><a href=\"https://www.therepository.email/wordpress-faces-an-event-horizon-not-a-sunset\">WordPress Faces an Event Horizon, Not a Sunset</a></strong>, <strong>Matt Cromwell</strong>, founder of Roots &amp; Fruits,  pushes back on the &#8220;WordPress is dying&#8221; narrative, reframing what looks like decline as an event horizon — a boundary where old rules break and new, denser ones form. AI, he argues, actually favors WordPress&#8217;s open, structured architecture. Flat plugin sales signal market maturity, not collapse. Educational pipelines are creating new builders. The real question isn&#8217;t whether WordPress survives, but whether its community will design for the physics ahead.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\">In this <a href=\"https://www.youtube.com/watch?v=gD-KgrQ_E_w\"><strong>WordPress AI experiments roundup</strong></a>, <strong>Jonathan Bossenger</strong> dives into community-submitted projects, starting with the WP AI Client Mistral provider, where he clones the repo, gets the AI SDK running, and generates a &#8220;WordPress haiku&#8221; post — though the model returns Markdown rather than block markup. He then tests a Claude-to-WordPress MCP integration plugin, successfully publishing a post directly from Claude, uses MCP Tracker to monitor requests, and briefly explores Ability Scout, which surfaces potential abilities from code.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Rich Tabor</strong> walks you through <a href=\"https://richtabor.com/wordpress-ai-client\" id=\"https://richtabor.com/wordpress-ai-client\" type=\"link\"><strong>the new WP AI Client landing in WordPress 7.0</strong></a> — a provider-agnostic layer for calling Anthropic, Google, OpenAI, and other AI models from both PHP and JavaScript, without plugins shipping their own API wrappers or credential pages. Configure once, use everywhere. His companion <a href=\"https://github.com/richtabor/wp-ai-content-kit\"><em>WP AI Content Kit</em></a> demonstrates auto-generating alt text and post excerpts using structured JSON responses. WordPress 7.0 is due April 9, coinciding with WordCamp Asia. </p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Glen Davies </strong>at Automattic introduces <a href=\"https://wordpress.com/blog/2026/02/13/new-plugin-and-skills-for-claude-cowork/\"><strong>new Skills and a Claude Cowork plugin</strong></a> that turns a conversation with Claude into a fully built block theme, deployed locally via WordPress Studio — no technical skills required. Describe your site, pick from design options, and Claude builds it. Setup takes about ten minutes and currently requires macOS. These tools are early and evolving fast, but the team wanted to ship them now rather than wait.</p>\n\n\n<div class=\"ng-block-cd6e3f599abfd985 wp-block-newsletterglue-container ng-block\" style=\"color: #666666;\" width=\"100%\"><div><div><div class=\"ng-block-vs ng-block-vs-1\" colspan=\"3\" height=\"0\" style=\"height: 0px;\"></div></div><div><div class=\"ng-block-hs ng-block-hs-1\" height=\"0\" style=\"width: 0px;\"></div><div align=\"none\" class=\"ng-block-td\" style=\"font-size: 16px; font-family: Helvetica; line-height: 1.6; font-weight: normal; padding-top: 20px; padding-bottom: 20px; padding-left: 0px; padding-right: 0px; text-align: none; color: #666666; background-color: #f8f8f8; border-radius: 8px;\"><div class=\"ng-block-e4eae9d8d5b20ab8 wp-block-newsletterglue-text ng-block\" style=\"color: #666666;\" width=\"100%\"><div><div><div align=\"none\" class=\"ng-block-td\" style=\"font-size: 16px; font-family: Helvetica; line-height: 1.6; font-weight: normal; padding-top: 8px; padding-bottom: 10px; padding-left: 20px; padding-right: 20px; text-align: none; color: #666666;\"><p><strong><a href=\"https://gutenbergtimes.com/need-a-zip-from-master/\">Need a plugin .zip from Gutenberg&#8217;s master branch?</a></strong><br />Gutenberg Times provides daily build for testing and review.</p></div></div></div></div>\n\n<div class=\"ng-block-f4ea75e02020326b wp-block-newsletterglue-image ng-block size-full is-resized\" width=\"100%\"><div><div><div align=\"center\" class=\"ng-block-td\" style=\"padding-top: 0px; padding-bottom: 0px; padding-left: 0px; padding-right: 0px;\"><a href=\"https://playground.wordpress.net/?blueprint-url=https://gutenbergtimes.com/wp-content/uploads/2020/11/playnightly.json\"><img alt=\"\" class=\"wp-image-42874 ng-image\" height=\"45\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2024/02/Screenshot-2025-11-15-at-12.06.44.png?resize=196%2C45&#038;ssl=1\" style=\"border-style: none; border-color: transparent;\" width=\"196\" /></a></div></div></div></div>\n\n<div class=\"ng-block-84050153471d616e wp-block-newsletterglue-text ng-block\" style=\"color: #666666;\" width=\"100%\"><div><div><div align=\"none\" class=\"ng-block-td\" style=\"font-size: 16px; font-family: Helvetica; line-height: 1.6; font-weight: normal; padding-top: 8px; padding-bottom: 10px; padding-left: 20px; padding-right: 20px; text-align: none; color: #666666;\"><p>Now also available via <a href=\"https://playground.wordpress.net/?blueprint-url=https://gutenbergtimes.com/wp-content/uploads/2020/11/playnightly.json\">WordPress Playground</a>. There is no need for a test site locally or on a server. Have you been using it? <a href=\"mailto:pauli@gutenbergtimes.com\">Email me </a>with your experience.</p></div></div></div></div></div><div class=\"ng-block-hs ng-block-hs-2\" height=\"0\" style=\"width: 0px;\"></div></div><div><div class=\"ng-block-vs ng-block-vs-2\" colspan=\"3\" height=\"0\" style=\"height: 0px;\"></div></div></div></div>\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"has-text-align-center has-small-font-size wp-block-paragraph\"><em>Questions? Suggestions? Ideas? </em><br /><em>Don&#8217;t hesitate to send <a href=\"mailto:pauli@gutenbergtimes.com\">them via email</a> or</em><br /><em> send me a message on WordPress Slack or Twitter @bph</em>.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"has-text-align-center has-small-font-size wp-block-paragraph\">For questions to be answered on the <a href=\"http://gutenbergtimes.com/podcast\">Gutenberg Changelog</a>, <br />send them to <a href=\"mailto:changelog@gutenbergtimes.com\">changelog@gutenbergtimes.com</a></p>\n\n\n<div class=\"ng-block-8617aca83b3f8b08 wp-block-newsletterglue-separator ng-block\" style=\"color: #666666;\" width=\"100%\"><div><div><div align=\"center\" class=\"ng-block-td\" style=\"padding-top: 20px; padding-bottom: 20px; padding-left: 20px; padding-right: 20px; color: #666666;\"><hr style=\"background-color: transparent; color: transparent; margin: 0; border: 0; border-top: 1px solid #666666; width: 560px; height: 0;\" /></div></div></div></div>\n\n<div class=\"wp-block-newsletterglue-showhide ng-block\" width=\"100%\"></div>\n\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sat, 28 Feb 2026 12:53:22 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:18:\"Birgit Pauli-Haack\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:38;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:68:\"Gutenberg Times: 14 ways to add Custom CSS in WordPress Block Editor\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://gutenbergtimes.com/?p=44344\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:79:\"https://gutenbergtimes.com/14-ways-to-add-custom-css-in-wordpress-block-editor/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:100197:\"<p class=\"wp-block-paragraph\">With the new Custom CSS on a block and post/page level, I was wondering if I would know where to look if something needs to be changed that was modified by a Custom CSS setting. Turns out there are 14 different ways to skin WordPress. I am a fan of keeping one source of truth, but it might not always be possible to keep it in theme.json. So I also wanted to figure out what decisions making process goes into selecting a method in the first place.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Below is a comprehensive reference for users, site builders, designers and developers covering all methods from no-code to full theme development.</p>\n\n\n\n<p class=\"wp-block-paragraph\">These methods only apply to Block themes, though. Classic theme methods (like the Customizer&#8217;s Additional CSS panel etc.) are excluded.</p>\n\n\n\n<div class=\"wp-block-group\"><div class=\"wp-block-group__inner-container is-layout-constrained wp-block-group-is-layout-constrained\">\n<p class=\"wp-block-paragraph\"><strong>Table of contents</strong></p>\n\n\n\n<nav class=\"wp-block-table-of-contents\"><ul><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/14-ways-to-add-custom-css-in-wordpress-block-editor/#the-specificity-cascade\">The specificity cascade</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/14-ways-to-add-custom-css-in-wordpress-block-editor/#1-theme-json-structured-style-properties\">1. theme.json — structured style properties</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/14-ways-to-add-custom-css-in-wordpress-block-editor/#2-theme-json-the-css-property\">2. theme.json — The css Property </a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/14-ways-to-add-custom-css-in-wordpress-block-editor/#3-custom-css-properties-variables-via-theme-json-settings\">3. Custom CSS Properties (Variables) via theme.json Settings</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/14-ways-to-add-custom-css-in-wordpress-block-editor/#4-child-theme-s-theme-json\">4. Child Theme&#8217;s theme.json</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/14-ways-to-add-custom-css-in-wordpress-block-editor/#5-global-styles-ui\">5. Global Styles UI </a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/14-ways-to-add-custom-css-in-wordpress-block-editor/#6-additional-css\">6. Additional CSS </a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/14-ways-to-add-custom-css-in-wordpress-block-editor/#7-per-block-additional-css\">7. Per-Block Additional CSS </a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/14-ways-to-add-custom-css-in-wordpress-block-editor/#8-additional-css-class-es-on-individual-block-instances\">8. Additional CSS Class(es) on individual block instances</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/14-ways-to-add-custom-css-in-wordpress-block-editor/#9-global-style-variations-theme-level-style-presets\">9. Global Style Variations (Theme-Level Style Presets)</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/14-ways-to-add-custom-css-in-wordpress-block-editor/#10-block-style-variations-json-php-and-javascript\">10. Block Style Variations (JSON, PHP, and JavaScript)</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/14-ways-to-add-custom-css-in-wordpress-block-editor/#11-section-styles\">11. Section Styles </a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/14-ways-to-add-custom-css-in-wordpress-block-editor/#12-block-stylesheets-via-wp-enqueue-block-style\">12. Block Stylesheets via wp_enqueue_block_style()</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/14-ways-to-add-custom-css-in-wordpress-block-editor/#13-enqueuing-stylesheets-via-wp-enqueue-style-in-php\">13. Enqueuing Stylesheets via wp_enqueue_style() in PHP</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/14-ways-to-add-custom-css-in-wordpress-block-editor/#14-the-theme-s-style-css\">14. The Theme&#8217;s style.css</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/14-ways-to-add-custom-css-in-wordpress-block-editor/#summary-table\">Summary Table</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/14-ways-to-add-custom-css-in-wordpress-block-editor/#decision-guide\">Decision Guide</a></li></ul></nav>\n</div></div>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"the-specificity-cascade\">The specificity cascade</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Before diving in, it helps to understand WordPress&#8217;s style hierarchy for block themes. Styles resolve in this order, with later layers overriding earlier ones on four levels.</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>Default </strong>mostly the styling and layouts of WordPress Core.</li>\n\n\n\n<li><strong>Block-level</strong> styling can be altered with plugins and overwrites the Default styling.</li>\n\n\n\n<li><strong>Theme-level </strong>styling is the whole suite of design tools controlled by the active Theme. It overwrites Default and block-level styles and layouts for instance (e.g. template and template parts).</li>\n\n\n\n<li><strong>User-level</strong> styling uses the Design tools within the Site Editor to modify styles and layouts. These changes are stored in the database and overwrite the theme-level styling.</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">Within each layer, more specific targets (per block, per element) override more general ones. This cascade is central to how all the methods below interact.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"1-theme-json-structured-style-properties\">1. theme.json — structured style properties</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Who:</strong> Theme developers, child theme authors<br /><strong>Where:</strong> <code>theme.json</code> (root of your theme) → <code>styles</code> section</p>\n\n\n\n<p class=\"wp-block-paragraph\">This is the <strong>recommended first choice</strong> for styling in block themes. Rather than writing raw CSS, you define styles as structured JSON properties — colors, typography, spacing, borders, shadows, and more — at the global, element, or per-block level.</p>\n\n\n\n<p class=\"wp-block-paragraph\">You can use hardcoded values directly in <code>styles</code>, and they work just fine:</p>\n\n\n\n<div class=\"wp-block-kevinbatdorf-code-block-pro cbp-has-line-numbers\"><span>JSON</span><span class=\"code-block-pro-copy-button\" style=\"color: #575279; display: none;\" tabindex=\"0\"><pre class=\"code-block-pro-copy-button-pre\"><textarea class=\"code-block-pro-copy-button-textarea\" readonly=\"readonly\" tabindex=\"-1\">{\n  \"version\": 3,\n  \"styles\": {\n    \"color\": {\n      \"background\": \"#ffffff\",\n      \"text\": \"#333333\"\n    },\n    \"elements\": {\n      \"link\": {\n        \"color\": { \"text\": \"#0073aa\" }\n      }\n    },\n    \"blocks\": {\n      \"core/button\": {\n        \"color\": { \"background\": \"#0073aa\" }\n      }\n    }\n  }\n}</textarea></pre><svg fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" viewBox=\"0 0 24 24\" xmlns=\"http://www.w3.org/2000/svg\"><path class=\"with-check\" d=\"M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-6 9l2 2 4-4\" stroke-linecap=\"round\" stroke-linejoin=\"round\"></path><path class=\"without-check\" d=\"M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"></path></svg></span><pre class=\"shiki rose-pine-dawn\" style=\"background-color: #faf4ed;\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color: #797593;\">{</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">  </span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">version</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #D7827E;\">3</span><span style=\"color: #797593;\">,</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">  </span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">styles</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #797593;\">{</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">    </span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">color</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #797593;\">{</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">      </span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">background</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">&quot;#ffffff&quot;</span><span style=\"color: #797593;\">,</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">      </span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">text</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">&quot;#333333&quot;</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">    </span><span style=\"color: #797593;\">},</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">    </span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">elements</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #797593;\">{</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">      </span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">link</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #797593;\">{</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">        </span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">color</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #797593;\">{</span><span style=\"color: #575279;\"> </span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">text</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">&quot;#0073aa&quot;</span><span style=\"color: #575279;\"> </span><span style=\"color: #797593;\">}</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">      </span><span style=\"color: #797593;\">}</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">    </span><span style=\"color: #797593;\">},</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">    </span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">blocks</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #797593;\">{</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">      </span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">core/button</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #797593;\">{</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">        </span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">color</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #797593;\">{</span><span style=\"color: #575279;\"> </span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">background</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">&quot;#0073aa&quot;</span><span style=\"color: #575279;\"> </span><span style=\"color: #797593;\">}</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">      </span><span style=\"color: #797593;\">}</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">    </span><span style=\"color: #797593;\">}</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">  </span><span style=\"color: #797593;\">}</span></span>\n<span class=\"line\"><span style=\"color: #797593;\">}</span></span></code></pre></div>\n\n\n\n<p class=\"wp-block-paragraph\">As your theme grows, hardcoded values become harder to manage. If you decide to change your primary color, you&#8217;d need to find and update every instance of <code>#0073aa</code> across styles. A more maintainable approach is to define your values as presets in the <code>settings</code> part of theme.json and then reference them in <code>styles</code> using the <code>var:preset||</code> syntax. WordPress converts these presets into CSS custom properties (e.g., <code>--wp--preset--color--primary</code>), keeping everything connected:</p>\n\n\n\n<div class=\"wp-block-kevinbatdorf-code-block-pro cbp-has-line-numbers\"><span>JSON</span><span class=\"code-block-pro-copy-button\" style=\"color: #575279; display: none;\" tabindex=\"0\"><pre class=\"code-block-pro-copy-button-pre\"><textarea class=\"code-block-pro-copy-button-textarea\" readonly=\"readonly\" tabindex=\"-1\">{\n  \"version\": 3,\n  \"settings\": {\n    \"color\": {\n      \"palette\": &#91;\n        { \"slug\": \"primary\", \"color\": \"#0073aa\", \"name\": \"Primary\" },\n        { \"slug\": \"base\", \"color\": \"#ffffff\", \"name\": \"Base\" },\n        { \"slug\": \"contrast\", \"color\": \"#333333\", \"name\": \"Contrast\" }\n      &#93;\n    },\n    \"typography\": {\n      \"fontSizes\": &#91;\n        { \"slug\": \"medium\", \"size\": \"18px\", \"name\": \"Medium\" }\n      &#93;\n    }\n  },\n  \"styles\": {\n    \"color\": {\n      \"background\": \"var:preset|color|base\",\n      \"text\": \"var:preset|color|contrast\"\n    },\n    \"typography\": {\n      \"fontSize\": \"var:preset|font-size|medium\",\n      \"lineHeight\": \"1.6\"\n    },\n    \"elements\": {\n      \"link\": {\n        \"color\": { \"text\": \"var:preset|color|primary\" }\n      },\n      \"heading\": {\n        \"typography\": { \"fontWeight\": \"700\" }\n      }\n    },\n    \"blocks\": {\n      \"core/button\": {\n        \"border\": { \"radius\": \"4px\" },\n        \"color\": { \"background\": \"var:preset|color|primary\" }\n      },\n      \"core/quote\": {\n        \"typography\": { \"fontStyle\": \"italic\" }\n      }\n    }\n  }\n}</textarea></pre><svg fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" viewBox=\"0 0 24 24\" xmlns=\"http://www.w3.org/2000/svg\"><path class=\"with-check\" d=\"M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-6 9l2 2 4-4\" stroke-linecap=\"round\" stroke-linejoin=\"round\"></path><path class=\"without-check\" d=\"M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"></path></svg></span><pre class=\"shiki rose-pine-dawn\" 